parameters.functionCode:
// Filtrar equipos que vencen mañana y hoy
const today = new Date();
const tomorrow = new Date(today);
tomorrow.setDate(tomorrow.getDate() + 1);

const formatDate = (date) => date.toISOString().split('T')[0];

const equipment = $input.all().map(item => item.json);

// Filtrar por fechas
const expiringTomorrow = equipment.filter(e => 
  e.tipo_propiedad === 'RENTADO' &&
  e.fecha_fin_renta === formatDate(tomorrow) &&
  !e.alerta_enviada &&
  e.ubicacion !== 'en_stock'
);

const expiringToday = equipment.filter(e => 
  e.tipo_propiedad === 'RENTADO' &&
  e.fecha_fin_renta === formatDate(today) &&
  e.ubicacion !== 'en_stock'
);

return [
  { json: { type: 'tomorrow', equipment: expiringTomorrow } },
  { json: { type: 'today', equipment: expiringToday } }
];

// Procesar equipos que vencen mañana
const data = $input.first().json;
const equipment = data.equipment;

if (equipment.length === 0) {
  return [{ json: { alerts_created: 0 } }];
}

const alerts = [];
for (const item of equipment) {
  alerts.push({
    user_id: item.user_id,
    tipo_alerta: 'renta_vence_manana',
    referencia_id: item.id,
    fecha_ejecucion: new Date().toISOString().split('T')[0],
    message: `⚠️ El ${item.nombre} rentado de ${item.proveedor_renta} vence mañana ${item.fecha_fin_renta}. ¿Ya lo devolviste?`
  });
}

return alerts.map(alert => ({ json: alert }));

// Actualizar equipos para marcar alerta enviada
const alerts = $input.all().map(item => item.json);
const equipmentIds = alerts.map(alert => alert.referencia_id);

return [{
  json: {
    equipment_ids: equipmentIds,
    alerts_created: alerts.length
  }
}];

// Enviar notificaciones para equipos que vencen hoy
const data = $input.first().json;
const equipment = data.equipment;

if (equipment.length === 0) {
  return [{ json: { urgent_alerts: 0 } }];
}

const urgentAlerts = [];
for (const item of equipment) {
  urgentAlerts.push({
    user_id: item.user_id,
    tipo_alerta: 'renta_vence_hoy',
    referencia_id: item.id,
    fecha_ejecucion: new Date().toISOString().split('T')[0],
    message: `🚨 HOY devuelve: ${item.nombre} a ${item.proveedor_renta}`
  });
}

return urgentAlerts.map(alert => ({ json: alert }));

// Preparar resumen para notificación
const tomorrowAlerts = $node["Insertar Alertas Mañana"].json;
const todayAlerts = $node["Insertar Alertas Hoy"].json;

const summary = {
  date: new Date().toISOString().split('T')[0],
  tomorrow_count: tomorrowAlerts?.length || 0,
  today_count: todayAlerts?.length || 0,
  total_alerts: (tomorrowAlerts?.length || 0) + (todayAlerts?.length || 0)
};

return [{ json: summary }];

